/* DocumentReceiveMapper.updateItemListCompleteUpload */
UPDATE NMCP_DOC_RCV_ITEM
   SET STATUS = 'Y'
       , RCV_DT = SYSDATE
       , AMD_ID = #{serviceId}
       , AMD_DT = SYSDATE
 WHERE DOC_RCV_ID = #{docRcvId}
   AND STATUS = 'P'
   AND ITEM_SEQ IN

    #{item.itemSeq}

/* DocumentReceiveMapper.updateItemListPendingToNotReceive */
UPDATE NMCP_DOC_RCV_ITEM
   SET STATUS = 'N'
       , AMD_ID = #{serviceId}
       , AMD_DT = SYSDATE
WHERE DOC_RCV_ID = #{docRcvId}
  AND STATUS = 'P'

UPDATE NMCP_DOC_RCV
   SET SCAN_ID = #{scanId}
       , AMD_ID = #{serviceId}
       , AMD_DT = SYSDATE
 WHERE DOC_RCV_ID = #{docRcvId}

UPDATE NMCP_DOC_RCV_ITEM
SET STATUS = 'Y'
  , RCV_DT = SYSDATE
  , AMD_ID = #{serviceId}
  , AMD_DT = SYSDATE
WHERE DOC_RCV_ID = #{docRcvId}
  AND STATUS = 'P'
  AND ITEM_SEQ = #{itemSeq}


    SELECT SQ_DOC_RCV_ITEM.NEXTVAL FROM DUAL

INSERT INTO NMCP_DOC_RCV_ITEM (
    ITEM_SEQ
    , DOC_RCV_ID
    , ITEM_ID
    , STATUS
    , RCV_DT
    , CRET_ID
    , CRET_DT
) VALUES (
    #{itemSeq}
    , #{docRcvId}
    , #{itemId}
    , 'Y'
    , SYSDATE
    , #{serviceId}
    , SYSDATE
)

UPDATE NMCP_DOC_RCV_ITEM
SET STATUS = 'E'
  , RCV_DT = SYSDATE
  , AMD_ID = #{serviceId}
  , AMD_DT = SYSDATE
WHERE DOC_RCV_ID = #{docRcvId}
  AND STATUS = 'P'
  AND ITEM_SEQ = #{itemSeq}


    SELECT SQ_DOC_RCV_ITEM.NEXTVAL FROM DUAL

INSERT INTO NMCP_DOC_RCV_ITEM (
    ITEM_SEQ
    , DOC_RCV_ID
    , ITEM_ID
    , STATUS
    , RCV_DT
    , CRET_ID
    , CRET_DT
